      "source_requirement": "When the finish date is reached, the rate is no longer valid and is considered expired.",
      "rewritten_requirement": "The system shall mark the rate as expired once the finish date is reached."
    },
    {
      "source_requirement": "After a certain period of time, such as one year from its expiration, the system automatically removes or archives the rate.",
      "rewritten_requirement": "The system shall remove or archive the rate after one year from its expiration date."
    }
  ]
}
